pub fn stop(self: *Server) void {
    self.running = false;
    if (self.listen_fd >= 0) {
        _ = std.c.close(self.listen_fd);
        self.listen_fd = -1;
    }
    var path_buf: [256]u8 = .{0} ** 256;
    if (self.socket_path.len < path_buf.len) {
