fn handleClientResize(self: *Server, client_idx: usize, payload: []const u8) void {
    if (payload.len < @sizeOf(protocol.ResizeMsg)) return;
    const msg: *const protocol.ResizeMsg = @alignCast(@ptrCast(payload.ptr));
