    var direction: Window.SwapDirection = .next;
    for (args) |arg| {
        if (std.mem.eql(u8, arg, "-U")) {
            direction = .prev;
        } else if (std.mem.eql(u8, arg, "-D")) {
            direction = .next;
        }
    }

    window.swapActivePane(direction);
}

