fn cmdKillSession(ctx: *Context, args: []const []const u8) CmdError!void {
    var kill_all_others = false;
    var clear_alerts = false;
    var target: ?[]const u8 = parseNamedOption(args, "-t");
    for (args) |arg| {
        if (std.mem.eql(u8, arg, "-a")) kill_all_others = true;
        if (std.mem.eql(u8, arg, "-C")) clear_alerts = true;
    }

    // -C: clear alerts on target/current session instead of killing
    if (clear_alerts) {
        const session: *Session = if (target) |name|
            ctx.server.findSession(name) orelse return CmdError.SessionNotFound
        else
            ctx.session orelse return CmdError.SessionNotFound;
        session.flags.alerted = false;
        return;
    }

    // -a: kill all sessions except the target
    if (kill_all_others) {
        const keep: ?*Session = if (target) |name|
            ctx.server.findSession(name) orelse return CmdError.SessionNotFound
        else
            ctx.session;
        var to_remove: std.ArrayListAligned(*Session, null) = .empty;
        defer to_remove.deinit(ctx.allocator);
        for (ctx.server.sessions.items) |session| {
            if (session != keep) to_remove.append(ctx.allocator, session) catch return CmdError.OutOfMemory;
        }
        for (to_remove.items) |session| {
            if (ctx.session == session) ctx.session = null;
            ctx.server.removeSession(session);
        }
        return;
    }

    if (target) |name| {
        const session = ctx.server.findSession(name) orelse return CmdError.SessionNotFound;
        if (ctx.session == session) ctx.session = null;
        ctx.server.removeSession(session);
    } else if (ctx.session) |session| {
        ctx.session = null;
        ctx.server.removeSession(session);
    } else {
        return CmdError.SessionNotFound;
    }
}
